1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	export type Step = QuoteStep;
14	
15	export interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	export interface QuoteResult {
21	  premium: number;
22	}
23	
24	export interface ScenarioResult {
25	  results: QuoteResult[];
26	}
27	
28	const PROCESSING_FEE = 5;
29	
30	const BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	};
37	
38	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
39	
40	const sumBasePremiums = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
42	
43	const quote = (items: Item[]): QuoteResult => ({
44	  premium: sumBasePremiums(items) + PROCESSING_FEE,
45	});
46	
47	export const runScenario = (scenario: Scenario): ScenarioResult => ({
48	  results: scenario.steps.map((step) => quote(step.items)),
49	});
50

